import { Badge } from "@/components/ui/badge";
import type { InternStatus } from "@/lib/types";

const statusVariant: Record<InternStatus, "muted" | "amber" | "teal"> = {
  Applied: "muted",
  Offered: "amber",
  Joined: "teal",
  Completed: "teal",
  Relieved: "muted"
};

export function StatusBadge({ status }: { status: InternStatus }) {
  return <Badge variant={statusVariant[status]}>{status}</Badge>;
}

